const rows = items
  .map((item) => item.json || {})
  .filter((row) => Object.keys(row).length > 0 && (row.lead_id || row.dedup_key || row.phone || row.email));

return [{
  json: {
    valid_leads: rows,
    valid_leads_count: rows.length,
  },
}];

const isProcessed = (value) => {
  if (value === true) return true;
  const normalized = String(value ?? '').trim().toLowerCase();
  return ['true', 'yes', '1', 'processed', 'done'].includes(normalized);
};

const text = (value) => String(value ?? '').trim();
const email = (value) => text(value).toLowerCase();
const phone = (value) => text(value).replace(/\D/g, '');
const validEmail = (value) => /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(value);
const nowIso = () => new Date().toISOString();
const safeId = (value) => String(value).replace(/[^a-zA-Z0-9]+/g, '_').replace(/^_+|_+$/g, '').slice(0, 64);
const telegramSafe = (value) => text(value)
  .replace(/&/g, 'and')
  .replace(/[<>]/g, '')
  .replace(/[_*`\[\]()~>#+\-=|{}.!]/g, ' ')
  .replace(/\s+/g, ' ')
  .trim();

const incoming = $items('Read incoming_leads').map((item, index) => ({
  ...item.json,
  _source_row_number: item.json.row_number ?? item.json.rowNumber ?? item.json.__rowNumber ?? item.json._rowNumber ?? index + 2,
}));

const seedItems = $items('Seed valid context');
const existing = seedItems.length ? (seedItems[0].json.valid_leads || []) : [];
const seenByContact = new Map();

const addSeen = (key, lead) => {
  if (key && !seenByContact.has(key)) seenByContact.set(key, lead);
};

for (const row of existing) {
  const normalizedPhone = phone(row.phone_normalized || row.phone);
  const normalizedEmail = email(row.email_normalized || row.email);
  const primaryKey = text(row.dedup_key);
  const lead = {
    lead_id: text(row.lead_id),
    dedup_key: primaryKey,
    source: text(row.source),
    name: text(row.name),
    email: text(row.email || row.email_normalized),
    phone: text(row.phone || row.phone_normalized),
  };
  addSeen(primaryKey, lead);
  addSeen(normalizedPhone.length >= 7 ? `phone:${normalizedPhone}` : '', lead);
  addSeen(validEmail(normalizedEmail) ? `email:${normalizedEmail}` : '', lead);
}

const output = [];

for (const row of incoming) {
  if (isProcessed(row.processed)) continue;

  const createdAt = text(row.created_at);
  const source = text(row.source);
  const name = text(row.name);
  const rawPhone = text(row.phone);
  const rawEmail = text(row.email);
  const message = text(row.message);
  const utmSource = text(row.utm_source);
  const normalizedPhone = phone(rawPhone);
  const normalizedEmail = email(rawEmail);
  const phoneOk = normalizedPhone.length >= 7;
  const emailOk = normalizedEmail ? validEmail(normalizedEmail) : false;
  const phoneKey = phoneOk ? `phone:${normalizedPhone}` : '';
  const emailKey = emailOk ? `email:${normalizedEmail}` : '';

  const errors = [];
  if (!createdAt) errors.push('missing_created_at');
  if (!source) errors.push('missing_source');
  if (!phoneOk && !emailOk) errors.push('missing_or_invalid_contact');

  const dedupKey = phoneKey || emailKey;
  const processedAt = nowIso();
  const phoneMatch = phoneKey ? seenByContact.get(phoneKey) : null;
  const emailMatch = emailKey ? seenByContact.get(emailKey) : null;
  const match = phoneMatch || emailMatch || null;
  const isValid = errors.length === 0;
  const isDuplicate = isValid && Boolean(match);
  const leadId = isDuplicate ? match.lead_id : dedupKey ? `demo_${safeId(dedupKey)}` : '';

  let action = 'valid_lead_created';
  let status = 'valid';
  let auditMessage = 'New valid lead appended';
  let notes = 'New valid lead';
  let errorReason = '';
  let duplicateReason = '';
  let matchedLeadId = '';

  if (!isValid) {
    action = 'invalid_lead';
    status = 'invalid';
    auditMessage = 'Lead did not pass validation';
    errorReason = errors.join(', ');
    notes = errorReason;
  } else if (isDuplicate) {
    action = 'duplicate_detected';
    status = 'duplicate';
    auditMessage = 'Duplicate lead logged';
    duplicateReason = match.dedup_key === dedupKey ? 'dedup_key_exists_in_valid_leads_or_current_batch' : 'alternate_contact_key_exists_in_valid_leads_or_current_batch';
    matchedLeadId = match.lead_id;
    notes = 'Duplicate lead detected';
  } else {
    const lead = { lead_id: leadId, dedup_key: dedupKey, source, name, email: rawEmail, phone: rawPhone };
    addSeen(dedupKey, lead);
    addSeen(phoneKey, lead);
    addSeen(emailKey, lead);
  }

  const rawPayload = JSON.stringify({ created_at: createdAt, source, name, phone: rawPhone, email: rawEmail, message, utm_source: utmSource });

  output.push({
    json: {
      source_row_number: row._source_row_number,
      processed_at: processedAt,
      created_at: createdAt,
      source,
      name,
      phone: rawPhone,
      email: rawEmail,
      phone_normalized: normalizedPhone,
      email_normalized: normalizedEmail,
      message,
      utm_source: utmSource,
      raw_payload: rawPayload,
      dedup_key: dedupKey,
      lead_id: leadId,
      is_invalid: !isValid,
      is_duplicate: isDuplicate,
      matched_lead_id: matchedLeadId,
      duplicate_reason: duplicateReason,
      action,
      status,
      notes,
      error_reason: errorReason,
      audit_message: auditMessage,
      telegram_new_message: `New qualified lead\nName: ${telegramSafe(name) || 'not provided'}\nContact: ${telegramSafe(normalizedPhone) || 'no phone'} / ${telegramSafe(normalizedEmail) || 'no email'}\nSource: ${telegramSafe(source) || 'unknown'}\nUTM: ${telegramSafe(utmSource) || 'none'}\nAction: added to valid leads`,
      telegram_duplicate_message: `Duplicate lead detected\nName: ${telegramSafe(name) || 'not provided'}\nDedup key: ${telegramSafe(dedupKey) || 'none'}\nMatched lead: ${telegramSafe(matchedLeadId) || 'unknown'}\nAction: logged to duplicates`,
      telegram_invalid_message: `Invalid lead\nSource: ${telegramSafe(source) || 'unknown'}\nName: ${telegramSafe(name) || 'not provided'}\nReason: ${telegramSafe(errorReason) || 'unknown'}\nAction: logged to invalid leads`,
    },
  });
}

return output;

